    public void Dispose() {
        Dispose(true);
        GC.SuppressFinalize(this);
    }

    protected virtual void Dispose(bool disposing) {
        if (!_disposed) {
            if (disposing) { /* Освободи управлявани ресурси */ }
            _disposed = true;
        }
    }
}

